// Normalize both entry points (hosted form + webhook) into one canonical lead object.
const src = $json.body ? $json.body : $json;

const pick = (...keys) => {
  for (const k of keys) {
    const v = src[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};

const name = pick('Full Name', 'name', 'full_name', 'fullName');
const email = pick('Work Email', 'email', 'work_email').toLowerCase();
const company = pick('Company Name', 'company', 'company_name');
const companySize = pick('Company Size', 'company_size', 'companySize');
const role = pick('Your Role', 'role', 'job_title', 'title');
const timeline = pick('When do you want to start?', 'timeline', 'start');
const budget = pick('Monthly budget for this project', 'budget');
const message = pick('What do you need help with?', 'message', 'notes');
const source = pick('source', 'utm_source') || ($json.body ? 'webhook' : 'n8n-form');
const campaign = pick('campaign', 'utm_campaign');

const validEmail = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email);
const emailDomain = validEmail ? email.split('@')[1] : '';
const FREE_DOMAINS = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'aol.com', 'icloud.com', 'proton.me', 'protonmail.com', 'gmx.com', 'mail.com', 'yandex.com', 'zoho.com'];
const isFreeEmail = FREE_DOMAINS.includes(emailDomain);

return {
  json: {
    name,
    email,
    emailDomain,
    isFreeEmail,
    validEmail,
    company,
    companySize,
    role,
    timeline,
    budget,
    message,
    source,
    campaign,
    capturedAt: new Date().toISOString(),
    status: 'new'
  }
};

// Merge enrichment results back onto the lead.
// If the Hunter node is disabled (default) or failed, the lead passes through unchanged.
const lead = $('Normalize & Validate Lead').item.json;
const resp = $json;

if (!resp || !resp.data || typeof resp.data !== 'object') {
  return { json: lead };
}

const v = resp.data;
return {
  json: {
    ...lead,
    emailStatus: v.status || 'unknown',
    emailConfidence: v.score ?? '',
    enriched: true
  }
};

// ---- Lead scoring engine: 0-100 points ----
// Fit (max 40) + Intent (max 45) + Source (max 15) - penalties.
// Tune every table below to YOUR ideal customer profile.
const lead = $json;
let score = 0;
const breakdown = {};

// --- Fit: company size (max 15) ---
const sizeScores = { 'Just me': 3, '2-10': 8, '11-50': 12, '51-200': 15, '201-1000': 15, '1000+': 12 };
const sizePts = sizeScores[lead.companySize] ?? 5;
score += sizePts;
breakdown.companySize = sizePts;

// --- Fit: role / seniority (max 15) ---
const roleScores = { 'Founder / C-Level': 15, 'VP / Director': 12, 'Manager / Team Lead': 8, 'Individual Contributor': 3, 'Student / Other': 0 };
const rolePts = roleScores[lead.role] ?? 5;
score += rolePts;
breakdown.role = rolePts;

// --- Fit: business email (max 10) ---
const emailPts = lead.isFreeEmail ? 0 : 10;
score += emailPts;
breakdown.businessEmail = emailPts;

// --- Intent: timeline (max 20) ---
const timelineScores = { 'Right away': 20, 'Within 1-3 months': 15, 'In 3-6 months': 8, 'Just researching': 2 };
const timePts = timelineScores[lead.timeline] ?? 5;
score += timePts;
breakdown.timeline = timePts;

// --- Intent: budget (max 15) ---
const budgetScores = { 'Over $10,000': 15, '$2,000 - $10,000': 12, '$500 - $2,000': 8, 'Under $500': 3, 'Not sure yet': 5 };
const budgetPts = budgetScores[lead.budget] ?? 5;
score += budgetPts;
breakdown.budget = budgetPts;

// --- Intent: buying-signal keywords in the message (max 10) ---
const msg = (lead.message || '').toLowerCase();
const hotWords = ['demo', 'pricing', 'quote', 'proposal', 'urgent', 'asap', 'call', 'migrate', 'switch', 'buy'];
let kwPts = 0;
for (const w of hotWords) {
  if (msg.includes(w)) kwPts += 5;
}
kwPts = Math.min(kwPts, 10);
score += kwPts;
breakdown.intentKeywords = kwPts;

// --- Source quality (max 15) ---
const sourceScores = { 'demo-request': 15, 'pricing-page': 12, 'referral': 12, 'webinar': 10, 'linkedin': 8, 'newsletter': 5, 'n8n-form': 5, 'webhook': 5 };
const srcPts = sourceScores[(lead.source || '').toLowerCase()] ?? 3;
score += srcPts;
breakdown.source = srcPts;

// --- Negative signals ---
let penalty = 0;
if ((lead.role || '') === 'Student / Other') penalty += 10;
const spamWords = ['test test', 'asdf', 'seo services', 'backlink', 'guest post', 'crypto airdrop'];
for (const w of spamWords) {
  if (msg.includes(w)) { penalty += 15; break; }
}
if (lead.emailStatus === 'invalid') penalty += 30;
score -= penalty;
breakdown.penalties = -penalty;

score = Math.max(0, Math.min(100, score));
const grade = score >= 70 ? 'HOT' : score >= 40 ? 'WARM' : 'COLD';

return { json: { ...lead, score, grade, scoreBreakdown: JSON.stringify(breakdown) } };

